  district: input.district || null,
  timezone: "America/Santiago"
}];

const input = $json;

const durationMinutes = Number(input.duration_minutes || 120);
const daysAhead = Number(input.days_ahead || 14);
const maxSlots = Number(input.max_slots || 3);

// ===============================
// CONFIGURACIÓN DE DISPONIBILIDAD
// ===============================

// 0 = domingo
// 1 = lunes
// 2 = martes
// 3 = miércoles
// 4 = jueves
// 5 = viernes
// 6 = sábado

const availabilityRules = [
  {
    weekday: 2, // martes
    times: ["09:00"]
  },
  {
    weekday: 4, // jueves
    times: ["09:00"]
  },
  {
    weekday: 0, // domingo
    times: ["09:00", "15:00"]
  }
];

// ===============================
// FUNCIONES INTERNAS
// ===============================

function pad(n) {
  return String(n).padStart(2, "0");
}

function getChileDateParts(date) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "America/Santiago",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    weekday: "short"
  }).formatToParts(date);

  const map = {};
  for (const part of parts) {
    map[part.type] = part.value;
  }

  return {
    year: Number(map.year),
    month: Number(map.month),
    day: Number(map.day)
  };
}

// Por ahora usamos UTC-4 para Chile.
// Más adelante se puede hacer dinámico si necesitas máxima precisión con cambio de hora.
function chileLocalToIso(year, month, day, hour, minute = 0) {
  const localString = `${year}-${pad(month)}-${pad(day)}T${pad(hour)}:${pad(minute)}:00-04:00`;
  return new Date(localString).toISOString();
}

function getWeekdayFromChileDate(year, month, day) {
  const date = new Date(`${year}-${pad(month)}-${pad(day)}T12:00:00-04:00`);
  return date.getUTCDay();
}

function parseTime(timeString) {
  const [hour, minute] = String(timeString).split(":").map(Number);

  if (!Number.isFinite(hour) || !Number.isFinite(minute)) {
    throw new Error(`Invalid time rule: ${timeString}`);
  }

  return { hour, minute };
}

// ===============================
// GENERAR HORARIOS CANDIDATOS
// ===============================

const now = new Date();
const candidates = [];

const startOffsetDays = Number(input.start_offset_days || 0);
const searchLengthDays = Number(input.days_ahead || 7);

for (let i = startOffsetDays; i <= startOffsetDays + searchLengthDays + 14; i++) {
  const future = new Date(now);
  future.setUTCDate(future.getUTCDate() + i);

  const parts = getChileDateParts(future);
  const weekday = getWeekdayFromChileDate(parts.year, parts.month, parts.day);

  const dayRule = availabilityRules.find(rule => rule.weekday === weekday);

  if (!dayRule) continue;

  for (const timeString of dayRule.times) {
    const { hour, minute } = parseTime(timeString);

    const startIso = chileLocalToIso(
      parts.year,
      parts.month,
      parts.day,
      hour,
      minute
    );

    const endIso = new Date(
      new Date(startIso).getTime() + durationMinutes * 60 * 1000
    ).toISOString();

    // Evita ofrecer horarios que ya pasaron
    if (new Date(startIso).getTime() <= now.getTime()) continue;

    const slotDate = `${parts.year}-${pad(parts.month)}-${pad(parts.day)}`;
    const slotTime = `${pad(hour)}:${pad(minute)}`;

    candidates.push({
      slot_id: `${slotDate}_${slotTime}`,
      booking_date: slotDate,
      booking_time: slotTime,
      slot_start_at: startIso,
      slot_end_at: endIso
    });
  }

  if (candidates.length >= maxSlots + 10) break;
}

if (candidates.length === 0) {
  return [{
    ...input,
    candidate_slots: [],
    search_start_at: now.toISOString(),
    search_end_at: new Date(now.getTime() + daysAhead * 24 * 60 * 60 * 1000).toISOString()
  }];
}

return [{
  ...input,
  candidate_slots: candidates,
  search_start_at: candidates[0].slot_start_at,
  search_end_at: candidates[candidates.length - 1].slot_end_at
}];

const base = $("generate_candidate_slots").first().json;

const busyEvents = Array.isArray($json.busy_events)
  ? $json.busy_events
  : [];

const candidateSlots = Array.isArray(base.candidate_slots)
  ? base.candidate_slots
  : [];

const maxSlots = Number(base.max_slots || 3);

function overlaps(slot, event) {
  const slotStart = new Date(slot.slot_start_at).getTime();
  const slotEnd = new Date(slot.slot_end_at).getTime();

  const eventStart = new Date(event.start_at).getTime();
  const eventEnd = new Date(event.end_at).getTime();

  if (!Number.isFinite(slotStart)) return false;
  if (!Number.isFinite(slotEnd)) return false;
  if (!Number.isFinite(eventStart)) return false;
  if (!Number.isFinite(eventEnd)) return false;

  return slotStart < eventEnd && slotEnd > eventStart;
}

const availableSlots = candidateSlots
  .filter(slot => !busyEvents.some(event => overlaps(slot, event)))
  .slice(0, maxSlots);

return [{
  success: true,
  lead_id: base.lead_id,
  calendar_id: base.calendar_id,
  service_interest: base.service_interest,
  vehicle_type: base.vehicle_type,
  district: base.district,
  duration_minutes: base.duration_minutes,
  days_ahead: base.days_ahead,
  start_offset_days: base.start_offset_days,
  max_slots: base.max_slots,
  availability_window: base.availability_window,
  availability_label: base.availability_label,
  slots: availableSlots,
  busy_events: busyEvents,
  checked_at: new Date().toISOString()
}];

